const headers = $input.first().json.headers;
const token = $env.DASHBOARD_API_TOKEN;

if (!token || headers['authorization'] !== `Bearer ${token}`) {
  throw new Error('UNAUTHORIZED');
}

return [{ json: { authorized: true } }];

const headers = $input.first().json.headers;
const token = $env.DASHBOARD_API_TOKEN;

if (!token || headers['authorization'] !== `Bearer ${token}`) {
  throw new Error('UNAUTHORIZED');
}

const query = $input.first().json.query || {};
return [{ json: { 
  authorized: true,
  limit: parseInt(query.limit) || 20,
  offset: parseInt(query.offset) || 0
}}];

const headers = $input.first().json.headers;
const params = $input.first().json.params;
const token = $env.DASHBOARD_API_TOKEN;

if (!token || headers['authorization'] !== `Bearer ${token}`) {
  throw new Error('UNAUTHORIZED');
}

if (!params.id) {
  throw new Error('Session ID required');
}

return [{ json: { 
  authorized: true,
  session_id: params.id
}}];

const headers = $input.first().json.headers;
const query = $input.first().json.query || {};
const token = $env.DASHBOARD_API_TOKEN;

if (!token || headers['authorization'] !== `Bearer ${token}`) {
  throw new Error('UNAUTHORIZED');
}

let days = 7;
if (query.period === '1d') days = 1;
else if (query.period === '30d') days = 30;
else if (query.period === '7d') days = 7;

return [{ json: { 
  authorized: true,
  days: days
}}];

const sessions = $('Query Sessions').all().map(r => ({
  id: r.json.id,
  created_at: r.json.created_at,
  message_count: parseInt(r.json.message_count) || 0,
  first_message: r.json.first_message ? r.json.first_message.substring(0, 100) : '',
  last_activity: r.json.last_activity,
  primary_intent: r.json.primary_intent || 'general'
}));

let total = 0;
try { total = parseInt($('Query Sessions Total').first().json.total) || 0; } catch(e) {}

return [{ json: { sessions, total } }];

let sessionInfo = null;
try { sessionInfo = $('Query Session Info').first().json; } catch(e) {}

let messages = [];
try { messages = $('Query Session Messages').all().map(r => r.json); } catch(e) {}

if (!sessionInfo || !sessionInfo.id) {
  return [{ json: { error: 'Session not found' } }];
}

return [{ json: {
  id: sessionInfo.id,
  created_at: sessionInfo.created_at,
  last_activity: sessionInfo.last_activity,
  metadata: sessionInfo.metadata || {},
  messages: messages
}}];

let sessionsPerDay = [];
try { sessionsPerDay = $('Query Sessions/Day').all().map(r => ({ date: r.json.date, count: parseInt(r.json.count) })); } catch(e) {}

let messagesPerHour = [];
try { messagesPerHour = $('Query Messages/Hour').all().map(r => ({ hour: parseInt(r.json.hour), count: parseInt(r.json.count) })); } catch(e) {}

let intents = [];
try { intents = $('Query Intents').all().map(r => ({ intent: r.json.intent, count: parseInt(r.json.count) })); } catch(e) {}

let topQuestions = [];
try { topQuestions = $('Query Top Questions').all().map(r => ({ question: r.json.question.substring(0, 80), count: parseInt(r.json.count) })); } catch(e) {}

return [{ json: {
  sessions_per_day: sessionsPerDay,
  messages_per_hour: messagesPerHour,
  intent_distribution: intents,
  top_questions: topQuestions
}}];
